        root = Node(char)  
    else:  
        current = root  
        while True:  
            if char < current.value:  
                if current.left is None:  
                    current.left = Node(char)  
                    break  
                else:  
                    current = current.left  
            elif char > current.value:  
                if current.right is None:  
                    current.right = Node(char)  
                    break  
                else:  
                    current = current.right  

